using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using BenchmarkDotNet.Toolchains.CsProj;
using TextAnalysis;

var config = DefaultConfig.Instance
    .AddJob(Job.Default.WithToolchain(CsProjCoreToolchain.NetCoreApp90).AsBaseline())
    .AddJob(Job.Default.WithToolchain(CsProjCoreToolchain.NetCoreApp10_0));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config, args);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // Generate a realistic body of text (~10k words)
        var rng = new Random(42);
        var sampleWords = new[]
        {
            "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
            "a", "an", "is", "was", "performance", "benchmarking", "dotnet",
            "optimization", "analysis", "text", "word", "length", "histogram",
            "unique", "count", "average", "compute", "data", "structure",
            "algorithm", "complexity", "efficiency", "runtime", "memory",
            "allocation", "garbage", "collector", "span", "buffer", "array"
        };
        var words = new string[10_000];
        for (int i = 0; i < words.Length; i++)
            words[i] = sampleWords[rng.Next(sampleWords.Length)];
        _analyzer = new TextAnalyzer(string.Join(' ', words));
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

