using System.Diagnostics;
using System.Runtime.CompilerServices;
using TextAnalysis;

// Build a ~10k-word input
var rng = new Random(42);
var sampleWords = new[]
{
    "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
    "a", "an", "is", "was", "performance", "benchmarking", "dotnet",
    "optimization", "analysis", "text", "word", "length", "histogram",
    "unique", "count", "average", "compute", "data", "structure",
    "algorithm", "complexity", "efficiency", "runtime", "memory",
    "allocation", "garbage", "collector", "span", "buffer", "array"
};
var words = new string[10_000];
for (int i = 0; i < words.Length; i++)
    words[i] = sampleWords[rng.Next(sampleWords.Length)];
var analyzer = new TextAnalyzer(string.Join(' ', words));

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Input: {analyzer.WordCount} words");
Console.WriteLine();

const int warmup = 500;
const int iterations = 5000;

Bench("AverageWordLength", () => analyzer.AverageWordLength());
Bench("WordLengthHistogram", () => analyzer.WordLengthHistogram());
Bench("UniqueWordCount", () => analyzer.UniqueWordCount());

static void Bench(string name, Func<object?> action)
{
    // Warmup
    for (int i = 0; i < warmup; i++)
        action();

    // Collect multiple samples for statistics
    const int sampleCount = 10;
    int opsPerSample = iterations / sampleCount;
    double[] sampleNs = new double[sampleCount];
    var sw = new Stopwatch();

    for (int s = 0; s < sampleCount; s++)
    {
        sw.Restart();
        for (int i = 0; i < opsPerSample; i++)
            action();
        sw.Stop();
        sampleNs[s] = (double)sw.ElapsedTicks / Stopwatch.Frequency * 1_000_000_000 / opsPerSample;
    }

    Array.Sort(sampleNs);
    double median = sampleNs[sampleCount / 2];
    double mean = sampleNs.Average();
    double min = sampleNs[0];
    double max = sampleNs[^1];

    Console.WriteLine($"{name,-25} median: {FormatNs(median),12}   mean: {FormatNs(mean),12}   min: {FormatNs(min),12}   max: {FormatNs(max),12}");
}

static string FormatNs(double ns)
{
    if (ns < 1_000) return $"{ns:F1} ns";
    if (ns < 1_000_000) return $"{ns / 1_000:F2} μs";
    return $"{ns / 1_000_000:F2} ms";
}

